mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM subject
    JOIN semester ON subject.semester_id = semester.id
    WHERE semester.user_id = #{reqUserId}
      AND semester.id = #{req.semesterId}
      AND subject.subject_name = #{req.subjectName}
      AND subject.deleted = false
)

mapper.sql:
WHERE subject.id is not null
AND subject.deleted = #{req.deleted}
AND subject.subject_name = #{req.subjectName}

mapper.select:
SELECT subject.id FROM subject JOIN semester ON subject.semester_id = semester.id
AND semester.user_id = #{reqUserId}
ORDER BY subject.id DESC
